    def create_payment(self, amount, currency, idempotency_key=None):
        if idempotency_key:
            existing = get_db().query(
                "SELECT * FROM payments WHERE idempotency_key = ?", idempotency_key
            )
            if existing:
                return existing, 409
        payment = self._process_payment(amount, currency)
        event_bus.emit('payment.created', payment)
        return payment, 201

    def refund(self, payment_id, amount):
        payment = get_db().query("SELECT * FROM payments WHERE id = ?", payment_id)
        available = payment['amount'] - payment.get('total_refunded', 0)
        if amount > available:
            raise ValueError(f"Refund amount {amount} exceeds remaining {available}")
        return self._process_refund(payment_id, amount)
